1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Step = QuoteStep;
4	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_FACTOR = 1.1;
8	const COMPONENT_BASE_PREMIUM = 25;
9	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
10	const COMPONENT_BLOCK_SIZE = 3;
11	
12	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	};
16	
17	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
18	
19	const countsByType = (items: Item[]): Map<string, number> => {
20	  const counts = new Map<string, number>();
21	  for (const item of items) {
22	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
23	  }
24	  return counts;
25	};
26	
27	const componentGroupBase = (count: number): number => {
28	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
29	  const leftover = count % COMPONENT_BLOCK_SIZE;
30	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
31	};
32	
33	const groupBasePremium = (type: string, count: number): number => {
34	  const mainBase = MAIN_ITEM_BASE_PREMIUM[type];
35	  return mainBase !== undefined ? mainBase * count : componentGroupBase(count);
36	};
37	
38	const sumItemPremiums = (items: Item[]): number => {
39	  let total = 0;
40	  for (const [type, count] of countsByType(items)) {
41	    total += groupBasePremium(type, count) * FIRST_INSURANCE_FACTOR;
42	  }
43	  return total;
44	};
45	
46	const priceQuote = (step: QuoteStep): { premium: number } => ({
47	  premium: ceilWithEpsilon(sumItemPremiums(step.items) + PROCESSING_FEE),
48	});
49	
50	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
51	  results: scenario.steps.map(priceQuote),
52	});
53

